// One body per loop
const row = items[0].json;

// ---------- Parse locations list ----------

let locations = [];
if (Array.isArray(row.locations_list)) {
  locations = row.locations_list;
} else if (typeof row.locations_list === 'string') {
  try {
    locations = JSON.parse(row.locations_list);
  } catch (e) {
    locations = [];
  }
} else if (row.locations_list && typeof row.locations_list === 'object') {
  locations = Object.values(row.locations_list);
}

locations = (locations || [])
  .map(n => String(n || '').trim())
  .filter(n => n.length > 0);

locations.sort((a, b) =>
  a.localeCompare(b, undefined, { sensitivity: 'base' }),
);

const totalLocations =
  Number(row.locations_total ?? locations.length) || 0;

// ---------- Classify body: planet vs moon ----------

const kindRaw = (row.body_kind || '').toLowerCase();
let bodyTypeDisplay = 'Planet';
let folderSegment = 'planets';

if (kindRaw.includes('moon')) {
  bodyTypeDisplay = 'Moon';
  folderSegment = 'moons';
}

// ---------- Shared header ----------

const headerLines = [];

headerLines.push(`# ${row.name}`);
headerLines.push('');

headerLines.push(`- **System:** ${row.system_name || 'Unknown'}`);
headerLines.push(`- **Body Type:** ${bodyTypeDisplay}`);
headerLines.push(`- **UEX Body ID:** ${row.uex_body_id || 'N/A'}`);
headerLines.push(`- **Locations:** ${totalLocations}`);
headerLines.push('');

// ---------- Helper: summary selection (max 5) ----------

function buildSummaryList(fullList, total) {
  if (total <= 5) {
    return {
      shown: [...fullList],
      suffix: '',
    };
  }
  const shown = fullList.slice(0, 5);
  const suffix = ` (${shown.length} of ${total})`;
  return { shown, suffix };
}

// ---------- SUMMARY VERSION ----------

const summaryLines = [...headerLines];

let { shown: locShown, suffix: locSuffix } =
  buildSummaryList(locations, totalLocations);

summaryLines.push(`## Locations on This Body${locSuffix}`);
summaryLines.push('');
summaryLines.push(
  '> _Note: Lists below are unordered and not ranked._',
);
summaryLines.push('');

if (locShown.length === 0) {
  summaryLines.push(
    '_No active locations are currently recorded on this body._',
  );
} else {
  for (const name of locShown) {
    summaryLines.push(`- ${name}`);
  }
  if (totalLocations > locShown.length) {
    summaryLines.push('Ã¢â‚¬Â¦ and more');
  }
}

// ---------- DETAILED VERSION ----------

const detailedLines = [...headerLines];

detailedLines.push(`## Locations on This Body`);
detailedLines.push('');
detailedLines.push(
  '> _Detailed view. Lists below are unordered and not ranked._',
);
detailedLines.push('');

if (locations.length === 0) {
  detailedLines.push(
    '_No active locations are currently recorded on this body._',
  );
} else {
  for (const name of locations) {
    detailedLines.push(`- ${name}`);
  }
}

// ---------- Slug + file paths (planets vs moons) ----------

const slug = (row.slug || row.name)
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '');

const filePathSummary = `/RAG/KB/${folderSegment}/${slug}.md`;
const filePathDetailed = `/RAG/KB/${folderSegment}/${slug}_detailed.md`;

return [
  {
    json: {
      body_id: row.id,
      slug,
      name: row.name,
      body_type: bodyTypeDisplay,
      folder: folderSegment,

      markdown_summary: summaryLines.join('\n'),
      filePath_summary: filePathSummary,

      markdown_detailed: detailedLines.join('\n'),
      filePath_detailed: filePathDetailed,
    },
  },
];

